// Noncompliant - class named Exception but doesn't extend it
public class FruitException
{
    private Fruit expected;
    private string unusualCharacteristics;
    private bool appropriateForCommercialExploitation;
}

compliant:
// Option 1: Extend Exception if it's truly an exception
public class FruitException : Exception
{
    public Fruit Expected { get; }

    public FruitException(Fruit expected, string message) : base(message)
    {
        Expected = expected;
    }
}

// Option 2: Rename if it's not an exception
public class FruitInspectionResult
{
    private Fruit expected;
    private string unusualCharacteristics;
    private bool appropriateForCommercialExploitation;
}
